import { isArray } from 'lodash-es';
import type { RequireAtLeastOne } from 'type-fest';

import {
  timeframeQueryClient,
  TIMEFRAME_PRESETS_QUERY_KEY,
} from './TimeframePresetsClient.js';
import type { Precision } from '../../../core/time/shared.types.js';
import type { Timeframe as TimeframeWithTimeValue } from '../../../core/types/time.js';
import { devLog } from '../../../core/utils/logging.js';
import { parseValue } from '../../../forms/forms-core/time/timeParser.js';

//#region API types
/** @internal - will come from the official SDK at some point. */
export interface Timeframe {
  from: string;
  to: string;
}

/** @internal - will come from the official SDK at some point. */
export interface TimeframePreset {
  id: string;
  timeframe: Timeframe;
}

/** @internal - will come from the official SDK at some point. */
export interface UserTimeframePresets {
  recentPresets: TimeframePreset[];
}
//#endregion

//#region type guards
/**
 * Makes sure the object is a Timeframe.
 * @internal
 */
export function isTimeframe(
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  timeframe: any,
): timeframe is Timeframe {
  if (typeof timeframe !== 'object') {
    return false;
  }
  return typeof timeframe.from === 'string' && typeof timeframe.to === 'string';
}
/**
 * Makes sure the object is a TimeframePreset.
 * @internal
 */
export function isTimeframePreset(
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  timeframePreset: any,
): timeframePreset is TimeframePreset {
  if (typeof timeframePreset !== 'object') {
    return false;
  }
  const hasValidId =
    timeframePreset.id !== undefined && typeof timeframePreset.id === 'string';
  const hasValidTimeframe =
    timeframePreset.timeframe && isTimeframe(timeframePreset.timeframe);
  return hasValidId && hasValidTimeframe;
}
/**
 * Makes sure the object is a UserTimeframePresets.
 * @internal
 */
export function isUserTimeframePresets(
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  userTimeframePreset: any,
): userTimeframePreset is UserTimeframePresets {
  if (typeof userTimeframePreset !== 'object' || userTimeframePreset === null) {
    return false;
  }
  const hasValidRecentPresets =
    isArray(userTimeframePreset.recentPresets) &&
    userTimeframePreset.recentPresets.every((recentPreset: unknown) =>
      isTimeframePreset(recentPreset),
    );

  return hasValidRecentPresets;
}
//#endregion

type GlobalThisType = typeof globalThis & {
  dtRuntime?: {
    timeframes?: {
      addRecentTimeframePreset(payload: {
        timeframe: Timeframe;
      }): Promise<UserTimeframePresets>;
      getTimeframePresets(): Promise<UserTimeframePresets>;
    };
  };
};

const RECENT_TIMEFRAME_SERVICE_UNAVAILABLE =
  'TimeframeSelector recent timeframe service is not available.';
const SAVE_RECENT_TIMEFRAME_ERROR =
  'TimeframeSelector failed to save recent timeframe.';
const GET_RECENT_TIMEFRAME_ERROR =
  'TimeframeSelector failed to get recent timeframes.';

/**
 * Function to add a timeframe preset to the user app state via the app shell runtime function for timeframe presets.
 * It only returns valid timeframePreset according to the `UserTimeframePresets`-type.
 * @internal
 */
export async function addRecentTimeframePreset(
  timeframe: Timeframe,
): Promise<UserTimeframePresets> {
  const dtRuntimeTimeframes = (globalThis as GlobalThisType).dtRuntime
    ?.timeframes;
  if (!dtRuntimeTimeframes?.addRecentTimeframePreset) {
    devLog(RECENT_TIMEFRAME_SERVICE_UNAVAILABLE);
    return { recentPresets: [] };
  }
  return dtRuntimeTimeframes
    .addRecentTimeframePreset({ timeframe })
    .then((presets) => {
      if (presets && isUserTimeframePresets(presets)) {
        return presets;
      }
      return { recentPresets: [] };
    })
    .catch(() => {
      devLog(SAVE_RECENT_TIMEFRAME_ERROR);
      return { recentPresets: [] };
    });
}

/**
 * Wrapper around `addRecentTimeframePreset`.
 * @internal
 */
export function saveRecentTimeframe(timeframe: TimeframeWithTimeValue): void {
  void addRecentTimeframePreset({
    from: timeframe.from.value,
    to: timeframe.to.value,
  })
    .then((presets) => {
      timeframeQueryClient.setQueryData(TIMEFRAME_PRESETS_QUERY_KEY, presets);

      return timeframeQueryClient.refetchQueries({
        queryKey: TIMEFRAME_PRESETS_QUERY_KEY,
        type: 'all',
      });
    })
    .catch(() => {
      // silently ignore errors - not critical if saving a recently used timeframe doesn't work
    });
}

/**
 * Function to get timeframe presets for the user app state via the app shell runtime function for timeframe presets.
 * It only returns valid timeframePreset according to the `UserTimeframePresets`-type.
 * @internal
 */
export async function getTimeframePresets(): Promise<UserTimeframePresets> {
  const dtRuntimeTimeframes = (globalThis as GlobalThisType).dtRuntime
    ?.timeframes;
  if (!dtRuntimeTimeframes?.getTimeframePresets) {
    devLog(RECENT_TIMEFRAME_SERVICE_UNAVAILABLE);
    return { recentPresets: [] };
  }
  return dtRuntimeTimeframes
    .getTimeframePresets()
    .then((presets) => {
      if (presets && isUserTimeframePresets(presets)) {
        return presets;
      }
      return { recentPresets: [] };
    })
    .catch(() => {
      devLog(GET_RECENT_TIMEFRAME_ERROR);
      return { recentPresets: [] };
    });
}

/**
 * Checks if a given timeframe value (preset) matches the currently selected timeframe.
 * If the preset is a recent timeframe it will not be displayed as selected in the UI.
 * @param value - The timeframe value of the preset to compare against.
 * @param details - The current value of the timeframe selector.
 * @param precision - The precision level (e.g., 'milliseconds', 'minutes', 'seconds') to consider.
 * @param isRecent - A boolean indicating whether the preset being checked is a recent timeframe.
 * @returns A boolean indicating whether the given preset should be displayed as selected.
 * @internal
 */
export function isPresetSelected(
  value: Timeframe,
  details: RequireAtLeastOne<TimeframeWithTimeValue> | null,
  isRecent: boolean,
  precision?: Precision,
): boolean {
  if (isRecent) {
    return false;
  }

  const selectedFrom = details?.from?.value;
  const selectedTo = details?.to?.value;

  const { from: presetFrom, to: presetTo } = parseValue(
    value,
    false,
    precision,
  );

  // only indicate selected state for presets, not for recent timeframes
  return (
    selectedFrom !== undefined &&
    selectedTo !== undefined &&
    selectedFrom === presetFrom?.value &&
    selectedTo === presetTo?.value
  );
}
